SELECT * FROM (SELECT _dataType.*, GETDATE() _evaluatedOn, DATE_TRUNC('MM', _ep.measurementPeriod.high) _partitionKey, STRUCT(STRING(_ep.measurementPeriod) key, _ep.measurementPeriod measurementPeriod) _parameters FROM {{ source('fhirlake', 'qdm__encounter_performed_v56') }} _dataType CROSS JOIN {{ ref('system__evaluation_period') }} _ep WHERE EXISTS (SELECT * FROM (SELECT explode(codes) codes FROM (SELECT codes FROM (WITH cy2024 AS (SELECT _c1 `oid`, _c0 `name`, _c2 `version`, _c8 `code`, _c9 `display`, _c10 `codeSystem`, _c11 `codeSystemOid`FROM CSV.`/mnt/zones/subenv/{{ env_var('workgroup_subenv') }}/specification/valueset/vsac/ec_eh_oqr_unique_vs_20230504.csv.gz`), all AS (SELECT t.oid, t.name, t.version, STRUCT(t.code, t.display, cs.url system) code FROM cy2024 t LEFT JOIN {{ source('fhirlake', 'terminology__codesystem') }} cs ON CONCAT('urn:oid:', t.codeSystemOid) = cs.identifier[0].value) SELECT oid, FIRST(name) name, version, COLLECT_LIST(code) codes FROM all GROUP BY oid, version) WHERE oid = "2.16.840.1.113883.3.117.1.7.1.424" ORDER BY version DESC LIMIT 1)) AS _vs WHERE _dataType.code.code = _vs.codes.code AND _dataType.code.system = _vs.codes.system)) AS NonElectiveEncounter WHERE ((DATEDIFF(NonElectiveEncounter.relevantPeriod.high, NonElectiveEncounter.relevantPeriod.low) <= 120) AND NonElectiveEncounter.relevantPeriod.high BETWEEN _parameters.measurementPeriod.low AND _parameters.measurementPeriod.high)